import React, { useState } from 'react';
import {
  Card,
  CardContent,
  Typography,
  TextField,
  Button,
  Table,
  TableHead,
  TableRow,
  TableCell,
  TableBody,
  Box,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  IconButton,
  Stack,
} from '@mui/material';
import AddIcon from '@mui/icons-material/Add';
import EditIcon from '@mui/icons-material/Edit';
import DeleteIcon from '@mui/icons-material/Delete';
import CloudUploadIcon from '@mui/icons-material/CloudUpload';

export default function HQDashboard() {
  const [open, setOpen] = useState(false);
  const [products, setProducts] = useState();

  const [form, setForm] = useState({
    name: '',
    details: '',
    price: '',
    image: null,
  });

  // Dialog কন্ট্রোল
  const handleOpen = () => setOpen(true);
  const handleClose = () => {
    setOpen(false);
    setForm({ name: '', details: '', price: '', image: null });
  };

  const handleImageChange = (e) => {
    setForm({ ...form, image: e.target.files[0] });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log('Submitting Product:', form);
    // এখানে API কল হবে (FormData ব্যবহার করে ইমেজ পাঠাতে হবে)
    handleClose();
  };

  return (
    <Box sx={{ padding: '24px' }}>
      {/* Header section with Create Button */}
      <Stack
        direction="row"
        justifyContent="space-between"
        alignItems="center"
        sx={{ marginBottom: '24px' }}
      >
        <Typography variant="h4" sx={{ fontWeight: 'bold', color: '#333' }}>
          Master Menu Management
        </Typography>
        <Button
          variant="contained"
          startIcon={<AddIcon />}
          onClick={handleOpen}
          sx={{
            borderRadius: '8px',
            textTransform: 'none',
            fontWeight: 'bold',
          }}
        >
          Add New Product
        </Button>
      </Stack>

      {/* Product List Table */}
      <Card
        variant="outlined"
        sx={{ boxShadow: '0 4px 12px rgba(0,0,0,0.05)', borderRadius: '12px' }}
      >
        <CardContent>
          <Table>
            <TableHead sx={{ backgroundColor: '#f9fafb' }}>
              <TableRow>
                <TableCell sx={{ fontWeight: 'bold' }}>Image</TableCell>
                <TableCell sx={{ fontWeight: 'bold' }}>Product Name</TableCell>
                <TableCell sx={{ fontWeight: 'bold' }}>Details</TableCell>
                <TableCell sx={{ fontWeight: 'bold' }}>Base Price</TableCell>
                <TableCell align="right" sx={{ fontWeight: 'bold' }}>
                  Actions
                </TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {products?.map((product) => (
                <TableRow key={product.id} hover>
                  <TableCell>
                    <Box
                      sx={{
                        width: 50,
                        height: 50,
                        backgroundColor: '#eee',
                        borderRadius: '8px',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                      }}
                    >
                      <Typography variant="caption">No Img</Typography>
                    </Box>
                  </TableCell>
                  <TableCell sx={{ fontWeight: '600' }}>
                    {product.name}
                  </TableCell>
                  <TableCell>{product.details}</TableCell>
                  <TableCell>৳{product.price}</TableCell>
                  <TableCell align="right">
                    <IconButton color="primary" size="small">
                      <EditIcon />
                    </IconButton>
                    <IconButton color="error" size="small">
                      <DeleteIcon />
                    </IconButton>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </CardContent>
      </Card>

      {/* Create/Edit Product Popup (Dialog) */}
      <Dialog open={open} onClose={handleClose} fullWidth maxWidth="sm">
        <DialogTitle sx={{ fontWeight: 'bold' }}>
          Create Master Menu Item
        </DialogTitle>
        <form onSubmit={handleSubmit}>
          <DialogContent>
            <Stack spacing={3} sx={{ mt: 1 }}>
              <TextField
                label="Product Name"
                fullWidth
                required
                value={form.name}
                onChange={(e) => setForm({ ...form, name: e.target.value })}
              />
              <TextField
                label="Details"
                fullWidth
                multiline
                rows={2}
                value={form.details}
                onChange={(e) => setForm({ ...form, details: e.target.value })}
              />
              <TextField
                label="Base Price"
                type="number"
                fullWidth
                required
                value={form.price}
                onChange={(e) => setForm({ ...form, price: e.target.value })}
              />

              {/* Image Upload Button */}
              <Button
                variant="outlined"
                component="label"
                startIcon={<CloudUploadIcon />}
                sx={{ padding: '12px' }}
              >
                {form.image ? form.image.name : 'Upload Product Image'}
                <input
                  type="file"
                  hidden
                  accept="image/*"
                  onChange={handleImageChange}
                />
              </Button>
            </Stack>
          </DialogContent>
          <DialogActions sx={{ padding: '16px 24px' }}>
            <Button onClick={handleClose} color="inherit">
              Cancel
            </Button>
            <Button type="submit" variant="contained" color="primary">
              Create Product
            </Button>
          </DialogActions>
        </form>
      </Dialog>
    </Box>
  );
}
